parameters.jsonBody:
={
  "message": "You are an expert social media copywriter and SEO specialist for Bridge Digital Solution agency.

Generate platform-optimised content for:
Brand: {{ $json.brand || 'Bridge Digital Solution' }}
Platform: {{ $json.platform || 'all' }}
Topic/Brief: {{ $json.brief }}
Tone: {{ $json.tone || 'professional yet engaging' }}
Content Pillar: {{ $json.pillar || 'educational' }}

Return ONLY valid JSON with this structure:
{
  "instagram": { "caption": "...", "hashtags": [], "seo_keywords": [], "cta": "..." },
  "facebook": { "caption": "...", "hashtags": [], "seo_keywords": [], "cta": "..." },
  "tiktok": { "caption": "...", "hashtags": [], "seo_keywords": [], "hook": "..." },
  "optimal_times": { "instagram": "18:00", "facebook": "13:00", "tiktok": "20:00" }
}

Instagram: max 2200 chars, 30 hashtags. Facebook: conversational, 5-10 hashtags. TikTok: punchy hook first, 10-15 hashtags.",
  "session_id": "smo-gen-{{ $now.toMillis() }}"
}

parameters.jsCode:
const raw = $json.response || $json.message || $json.output || $json.reply || '';
let content;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  content = JSON.parse(match ? match[0] : raw);
} catch(e) {
  content = { parse_error: true, raw: raw.substring(0, 500) };
}
const input = $('Webhook Entry').first().json;
return [{ json: {
  brand: input.brand || 'Bridge Digital Solution',
  brief: input.brief || '',
  platform: input.platform || 'all',
  image_url: input.image_url || null,
  video_url: input.video_url || null,
  ig_caption: content.instagram?.caption || '',
  ig_hashtags: JSON.stringify(content.instagram?.hashtags || []),
  fb_caption: content.facebook?.caption || '',
  fb_hashtags: JSON.stringify(content.facebook?.hashtags || []),
  tt_caption: content.tiktok?.caption || '',
  tt_hashtags: JSON.stringify(content.tiktok?.hashtags || []),
  tt_hook: content.tiktok?.hook || '',
  optimal_times: JSON.stringify(content.optimal_times || { instagram: '18:00', facebook: '13:00', tiktok: '20:00' }),
  content_raw: JSON.stringify(content),
  generated_at: new Date().toISOString()
} }];

// Instagram 2-step publish: create container → wait → publish
const igUserId = $env.META_IG_USER_ID;
const accessToken = $env.META_ACCESS_TOKEN;
const item = $json;
const igCaption = item.ig_caption || item.caption || '';
const igHashtags = item.ig_hashtags ? JSON.parse(item.ig_hashtags).join(' ') : '';
const fullCaption = igCaption + (igHashtags ? '\n\n' + igHashtags : '');

// Step 1: create container
const containerBody = {
  caption: fullCaption,
  access_token: accessToken
};
if (item.video_url) {
  containerBody.media_type = 'REELS';
  containerBody.video_url = item.video_url;
} else if (item.image_url) {
  containerBody.image_url = item.image_url;
} else {
  return [{ json: { platform: 'instagram', skipped: true, reason: 'no_media_url', caption: fullCaption } }];
}

const containerRes = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://graph.facebook.com/v19.0/${igUserId}/media`,
  headers: { 'Content-Type': 'application/json' },
  body: containerBody,
  json: true
});

if (!containerRes.id) {
  return [{ json: { platform: 'instagram', error: 'container_failed', detail: containerRes } }];
}

// Step 2: wait 20s for processing
await new Promise(r => setTimeout(r, 20000));

// Step 3: publish
const publishRes = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://graph.facebook.com/v19.0/${igUserId}/media_publish`,
  headers: { 'Content-Type': 'application/json' },
  body: { creation_id: containerRes.id, access_token: accessToken },
  json: true
});

return [{ json: { platform: 'instagram', id: publishRes.id, container_id: containerRes.id, caption: fullCaption } }];

const all = $input.all();
return [{ json: {
  published: all.map(i => ({ platform: i.json.platform || 'unknown', id: i.json.id || i.json.publish_id || 'queued', skipped: i.json.skipped || false })),
  count: all.length,
  timestamp: new Date().toISOString()
} }];

let ig = {}, fb = {}, tt = {};
try { ig = $('Fetch IG Insights').first().json; } catch(e) {}
try { fb = $('Fetch FB Page Insights').first().json; } catch(e) {}
try { tt = $('Fetch TikTok Analytics').first().json; } catch(e) {}

const igData = (ig.data || []).reduce((a, m) => { a[m.name] = m.values?.[0]?.value || 0; return a; }, {});
const fbData = (fb.data || []).reduce((a, m) => { a[m.name] = m.values?.[0]?.value || 0; return a; }, {});
const ttData = tt.data?.user_info || {};

return [{ json: {
  report_date: new Date().toISOString().split('T')[0],
  ig_reach: igData.reach || 0,
  ig_impressions: igData.impressions || 0,
  ig_followers: igData.follower_count || 0,
  ig_profile_views: igData.profile_views || 0,
  ig_engaged: igData.accounts_engaged || 0,
  fb_reach: fbData.page_reach || 0,
  fb_impressions: fbData.page_impressions || 0,
  fb_fans: fbData.page_fans || 0,
  fb_page_views: fbData.page_views_total || 0,
  fb_engaged: fbData.page_engaged_users || 0,
  tt_followers: ttData.follower_count || 0,
  tt_likes: ttData.likes_count || 0,
  tt_videos: ttData.video_count || 0,
  total_reach: (igData.reach || 0) + (fbData.page_reach || 0),
  total_impressions: (igData.impressions || 0) + (fbData.page_impressions || 0),
  total_followers: (igData.follower_count || 0) + (fbData.page_fans || 0) + (ttData.follower_count || 0)
} }];

