const drafts = $input.all();
if (!drafts.length) return [{ json: { skipped: true, reason: 'no_posts_today', count: 0 } }];
return drafts.map(d => ({ json: { ...d.json, action: 'publish_post' } }));

const m = $json;
const date = new Date().toLocaleDateString('en-GB', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const html = `<!DOCTYPE html><html><head><style>body{font-family:Arial,sans-serif;margin:0;padding:20px;background:#f5f5f5}.header{background:linear-gradient(135deg,#E1306C,#833AB4,#FD1D1D);color:white;padding:30px;border-radius:10px;margin-bottom:20px}.card{background:white;border-radius:10px;padding:20px;margin:15px 0;box-shadow:0 2px 8px rgba(0,0,0,.08)}.big{font-size:32px;font-weight:bold;color:#E1306C}.lbl{color:#888;font-size:13px}.green{color:#27ae60;font-weight:bold}</style></head><body><div class="header"><h1>Bridge Digital Solution</h1><p>Weekly Social Media Report — ${date}</p></div><div class="card"><h2>This Week</h2><div class="big">${Number(m.weekly_reach||0).toLocaleString()}</div><div class="lbl">Total Reach</div><br><div class="big" style="color:#833AB4">${Number(m.weekly_impressions||0).toLocaleString()}</div><div class="lbl">Total Impressions</div><br><div class="green">+${Number(m.follower_growth||0).toLocaleString()} followers gained</div></div><div class="card"><h2>Instagram</h2><div class="big">${Number(m.avg_ig_followers||0).toLocaleString()}</div><div class="lbl">Avg Followers</div></div><div class="card"><h2>Facebook</h2><div class="big" style="color:#1877F2">${Number(m.avg_fb_fans||0).toLocaleString()}</div><div class="lbl">Avg Page Fans</div></div><div class="card"><h2>TikTok</h2><div class="big" style="color:#010101">${Number(m.avg_tt_followers||0).toLocaleString()}</div><div class="lbl">Avg Followers</div></div><div class="card" style="background:#f0f8ff"><p style="color:#888;font-size:12px">Generated by Bridge Digital Solution Super Agent — Social Media SEO Orchestrator</p></div></body></html>`;
return [{ json: { html_report: html, subject: 'Social Media Weekly Report — ' + new Date().toLocaleDateString('en-GB'), metrics: m } }];

const action = $('Webhook Entry').first()?.json?.action || 'scheduled';
const data = $json;
const responseMap = {
  generate_content: { message: 'Content generated and saved as draft' },
  publish_post:     { message: 'Post published successfully' },
  get_analytics:   { message: 'Analytics fetched successfully' },
  seo_audit:       { message: 'SEO audit complete' },
  schedule_post:   { message: 'Post scheduled successfully' }
};
return [{ json: { success: true, action, ...(responseMap[action] || {}), data } }];
